+func sanitizeMailDisplayField(value string) string {
+	clean := status.StripANSI(value)
+	clean = strings.Map(func(r rune) rune {
+		switch {
+		case r == '\n' || r == '\r' || r == '\t':
+			return ' '
+		case unicode.IsControl(r):
+			return -1
+		default:
+			return r
+		}
+	}, clean)
+	return strings.Join(strings.Fields(clean), " ")
+}
